import sys

class Solution:
    def optimalTreasure(self, grid: list[list[int]]) -> int:
        if not grid or not grid[0]:
            return 0
        m, n = len(grid), len(grid[0])
        dp = [[[float('-inf')] * 3 for _ in range(n)] for _ in range(m)]

        val = grid[0][0]
        if val >= 0:
            dp[0][0][0] = val
            dp[0][0][1] = val
            dp[0][0][2] = val
        else:
            dp[0][0][0] = val
            dp[0][0][1] = 0
            dp[0][0][2] = 0

        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue

                val = grid[i][j]
                prev_states = []
                if i > 0:
                    prev_states.append(dp[i-1][j])
                if j > 0:
                    prev_states.append(dp[i][j-1])

                for state in prev_states:
                    dp[i][j][0] = max(dp[i][j][0], state[0] + val)

                    if val < 0:
                        dp[i][j][1] = max(dp[i][j][1], state[0], state[1] + val)
                        dp[i][j][2] = max(dp[i][j][2], state[1], state[2] + val)
                    else:
                        dp[i][j][1] = max(dp[i][j][1], state[1] + val)
                        dp[i][j][2] = max(dp[i][j][2], state[2] + val)

        return max(dp[m-1][n-1])

def main():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    m = int(input_data[0])
    n = int(input_data[1])
    grid = []
    idx = 2
    for i in range(m):
        row = []
        for j in range(n):
            row.append(int(input_data[idx]))
            idx += 1
        grid.append(row)

    sol = Solution()
    print(sol.optimalTreasure(grid))

if __name__ == "__main__":
    main()

from typing import List

class Solution:
    def findUniqueSignal(self, signals: List[int], w: int) -> int:
        window_count = {}

        n = len(signals)
        for i in range(n - w + 1):
            window = signals[i:i+w]
            unique_in_window = set(window)
            for val in unique_in_window:
                if val not in window_count:
                    window_count[val] = 0
                window_count[val] += 1

        result = -1
        for val, count in window_count.items():
            if count == 1:
                result = max(result, val)

        return result

def main():
    import sys
    lines = sys.stdin.read().strip().split('\n')

    signals = list(map(int, lines[0].split()))
    w = int(lines[1])

    solution = Solution()
    result = solution.findUniqueSignal(signals, w)
    print(result)

