using namespace std;

class Solution {
public:
    bool findUniformSegment(string sequence, int n) {
        int len = sequence.length();

        for (int i = 0; i <= len - n; i++) {
            bool allSame = true;
            char c = sequence[i];

            for (int j = i; j < i + n; j++) {
                if (sequence[j] != c) {
                    allSame = false;
                    break;
                }
            }

            if (allSame) {
                bool validBefore = (i == 0 || sequence[i - 1] != c);
                bool validAfter = (i + n == len || sequence[i + n] != c);

                if (validBefore && validAfter) {
                    return true;
                }
            }
        }

        return false;
    }
};

int main() {
    string sequence;
    int n;
    cin >> sequence >> n;

    Solution solution;
    bool result = solution.findUniformSegment(sequence, n);

    if (result) {
        cout << "true" << endl;
    } else {
        cout << "false" << endl;
    }

    return 0;
}

