import (
	"bufio"
	"encoding/json"
	"fmt"
	"os"
	"sort"
)

func solve() {
	reader := bufio.NewReader(os.Stdin)
	var hubsCount, allowance int

	line, _ := reader.ReadString('\n')
	fmt.Sscanf(line, "%d %d", &hubsCount, &allowance)

	var connections [][]int
	decoder := json.NewDecoder(reader)
	if err := decoder.Decode(&connections); err != nil {
		return
	}

	costs := make([]int, 0, len(connections))
	for _, conn := range connections {
		costs = append(costs, conn[2])
	}
	sort.Ints(costs)

	uniqueCosts := make([]int, 0)
	if len(costs) > 0 {
		uniqueCosts = append(uniqueCosts, costs[0])
		for i := 1; i < len(costs); i++ {
			if costs[i] != costs[i-1] {
				uniqueCosts = append(uniqueCosts, costs[i])
			}
		}
	}

	check := func(maxCost int) bool {
		adj := make([][]int, hubsCount)
		for _, conn := range connections {
			if conn[2] <= maxCost {
				adj[conn[1]] = append(adj[conn[1]], conn[0])
			}
		}

		visited := make([]bool, hubsCount)
		queue := make([]int, 0, hubsCount)

		visited[0] = true
		queue = append(queue, 0)

		count := 1
		head := 0
		for head < len(queue) {
			u := queue[head]
			head++
			for _, v := range adj[u] {
				if !visited[v] {
					visited[v] = true
					count++
					queue = append(queue, v)
				}
			}
		}
		return count == hubsCount
	}

	ans := -1
	low := 0
	high := len(uniqueCosts) - 1
	for low <= high {
		mid := low + (high-low)/2
		if check(uniqueCosts[mid]) {
			ans = uniqueCosts[mid]
			high = mid - 1
		} else {
			low = mid + 1
		}
	}

	fmt.Println(ans)
}

func main() {
	solve()
}

import sys

class Solution:
    def maxGameSegmentsSum(self, scores: list[int], p: int, n: int) -> int:
        length = len(scores)
        prefix_sum = [0] * (length + 1)
        for i in range(length):
            prefix_sum[i + 1] = prefix_sum[i] + scores[i]

        dp = [[-float('inf')] * (p + 1) for _ in range(length + 1)]
        for i in range(length + 1):
            dp[i][0] = 0

        for k in range(1, p + 1):
            best_prev_dp = -float('inf')
            for i in range(n * k, length + 1):
                best_prev_dp = max(best_prev_dp, dp[i - n][k - 1] - prefix_sum[i - n])
                dp[i][k] = max(dp[i - 1][k], prefix_sum[i] + best_prev_dp)

        return dp[length][p]

def main():
