import (
    "fmt"
)

const MOD = 1000000007

func modPow(base, exp, mod int64) int64 {
    result := int64(1)
    base %= mod
    for exp > 0 {
        if exp%2 == 1 {
            result = (result * base) % mod
        }
        base = (base * base) % mod
        exp /= 2
    }
    return result
}

func modInv(a, mod int64) int64 {
    return modPow(a, mod-2, mod)
}

func computeBinomial(n, k int) int64 {
    if k > n || k < 0 {
        return 0
    }
    if k == 0 || k == n {
        return 1
    }
    if k > n-k {
        k = n - k
    }

    num := int64(1)
    den := int64(1)

    for i := 0; i < k; i++ {
        num = (num * int64(n-i)) % MOD
        den = (den * int64(i+1)) % MOD
    }

    return (num * modInv(den, MOD)) % MOD
}

func solve(M, N, L int) int64 {
    total := M * N

    if L > total {
        return 0
    }

    binomCoeff := computeBinomial(total-2, L-2)

    rowSum := int64(0)
    for r1 := 0; r1 < M; r1++ {
        for r2 := r1 + 1; r2 < M; r2++ {
            dist := int64(r2 - r1)
            count := int64(N) * int64(N) % MOD
            contribution := (dist * count) % MOD
            contribution = (contribution * binomCoeff) % MOD
            rowSum = (rowSum + contribution) % MOD
        }
    }

    colSum := int64(0)
    for c1 := 0; c1 < N; c1++ {
        for c2 := c1 + 1; c2 < N; c2++ {
            dist := int64(c2 - c1)
            count := int64(M) * int64(M) % MOD
            contribution := (dist * count) % MOD
            contribution = (contribution * binomCoeff) % MOD
            colSum = (colSum + contribution) % MOD
        }
    }

    result := (rowSum + colSum) % MOD
    return result
}

func main() {
    var M, N, L int
    fmt.Scan(&M, &N, &L)

    result := solve(M, N, L)
    fmt.Println(result)
}

import sys

class Solution:
    def highestOccurrence(self, scores: list[int], target: int) -> int:
        n = len(scores)
        prefix_target = [0] * (n + 1)
        for i in range(n):
            prefix_target[i+1] = prefix_target[i] + (1 if scores[i] == target else 0)

        total_target = prefix_target[n]
        max_occ = total_target

        for v in range(1, 51):
            if v == target:
                continue

            current_gain = 0
            max_gain = 0
            for i in range(n):
                val = 0
                if scores[i] == v:
                    val = 1
                elif scores[i] == target:
                    val = -1

                current_gain += val
                if current_gain < 0:
                    current_gain = 0
                if current_gain > max_gain:
                    max_gain = current_gain

            if total_target + max_gain > max_occ:
                max_occ = total_target + max_gain

        return max_occ

def main():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    scores_str = ""
    target_str = ""

    idx = 0
    while idx < len(input_data):
        if input_data[idx].startswith("scores"):
            while idx < len(input_data) and "target" not in input_data[idx]:
                scores_str += input_data[idx]
                idx += 1
        if idx < len(input_data) and "target" in input_data[idx]:
            target_str = input_data[idx] + (input_data[idx+1] if idx+1 < len(input_data) else "")
            break
        idx += 1

    import re
    scores_match = re.search(r'\[(.*?)\]', scores_str)
    if scores_match:
        scores = [int(x) for x in scores_match.group(1).replace(',', ' ').split()]
    else:
        scores = []

    target_match = re.search(r'target\s*=\s*(\d+)', target_str)
    if target_match:
        target = int(target_match.group(1))
    else:
        target = 0

    if not scores:
        temp_nums = []
        for s in input_data:
            clean = re.sub(r'[^0-9]', '', s)
            if clean:
                temp_nums.append(int(clean))
        if temp_nums:
            target = temp_nums[-1]
            scores = temp_nums[:-1]

    sol = Solution()
    print(sol.highestOccurrence(scores, target))

if __name__ == "__main__":
    main()

class Solution:
    def computeMaxDisparity(self, seq: str) -> int:
        from collections import Counter

        counts = Counter(seq)

        odd_counts = []
        even_counts = []

        for char, count in counts.items():
            if count % 2 == 1:
                odd_counts.append(count)
            else:
                even_counts.append(count)

        max_odd = max(odd_counts)
        min_even = min(even_counts)

        return max_odd - min_even

def main():
    seq = input().strip()
    solution = Solution()
    result = solution.computeMaxDisparity(seq)
    print(result)

