import sys

class Solution:
    def countClusters(self, blueprints: List[List[int]], threshold: int) -> int:
        n = len(blueprints)

        def common_elements(arr1, arr2):
            set1 = set(arr1)
            set2 = set(arr2)
            return len(set1 & set2)

        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px = find(x)
            py = find(y)
            if px != py:
                parent[px] = py

        for i in range(n):
            for j in range(i + 1, n):
                if common_elements(blueprints[i], blueprints[j]) >= threshold:
                    union(i, j)

        clusters = len(set(find(i) for i in range(n)))
        return clusters

def main():
    lines = []
    for line in sys.stdin:
        lines.append(line.strip())

    blueprints_str = lines[0]
    threshold = int(lines[1])

    blueprints_str = blueprints_str.strip()
    blueprints = eval(blueprints_str)

    solution = Solution()
    result = solution.countClusters(blueprints, threshold)
    print(result)

