import sys

def count_dragon_crest(n_str):
    if not n_str:
        return 0
    n_val = int(n_str)
    if n_val < 10:
        return 0

    total = 0
    length = len(n_str)

    for l in range(2, length):
        for d in range(1, 10):
            total += d ** (l - 1)

    first_digit = int(n_str[0])
    for d in range(1, first_digit):
        total += d ** (length - 1)

    is_valid_prefix = True
    for i in range(1, length):
        limit = int(n_str[i])
        d_max = first_digit

        if limit < d_max:
            total += limit * (d_max ** (length - 1 - i))
        else:
            total += d_max * (d_max ** (length - 1 - i))
            is_valid_prefix = False
            break

    if is_valid_prefix:
        total += 1

    return total

def main():
