vector<long long> generatePrimes(long long limit) {
    vector<bool> isPrime(limit + 1, true);
    vector<long long> primes;
    isPrime[0] = isPrime[1] = false;
    for (long long i = 2; i <= limit; i++) {
        if (isPrime[i]) {
            primes.push_back(i);
            for (long long j = i * i; j <= limit; j += i) {
                isPrime[j] = false;
            }
        }
    }
    return primes;
}

long long solve(long long B) {
    vector<long long> primes = generatePrimes(1000000);
    long long maxMedallion = 0;

    for (size_t i = 0; i < primes.size(); i++) {
        long long p = primes[i];
        long long p2 = p * p;
        if (p2 > B) break;

        for (size_t j = i + 1; j < primes.size(); j++) {
            long long q = primes[j];
            long long q2 = q * q;
            if (p2 * q2 > B) break;

            long long powerP = p2;
            while (powerP <= B / q2) {
                long long maxQ2Power = B / powerP;
                long long powerQ = q2;
                long long lastValid = 0;

                while (powerQ <= maxQ2Power) {
                    lastValid = powerP * powerQ;
                    if (powerQ > maxQ2Power / q2) break;
                    powerQ *= q2;
                }

                if (lastValid > maxMedallion) {
                    maxMedallion = lastValid;
                }

                if (powerP > B / (p2)) break;
                powerP *= p2;
            }
        }
    }

    return maxMedallion;
}

