class Solution {
public:
    long long maxGameSegmentsSum(vector<int>& scores, int p, int n) {
        int m = scores.size();
        vector<long long> prefix(m + 1, 0);
        for (int i = 0; i < m; ++i) {
            prefix[i + 1] = prefix[i] + scores[i];
        }

        vector<vector<long long>> dp(p + 1, vector<long long>(m + 1, -2e18));

        for (int j = 0; j <= m; ++j) {
            dp[0][j] = 0;
        }

        for (int i = 1; i <= p; ++i) {
            long long maxPrev = -2e18;
            for (int j = n; j <= m; ++j) {
                maxPrev = max(maxPrev, dp[i - 1][j - n] - prefix[j - n]);
                dp[i][j] = max(dp[i][j - 1], maxPrev + prefix[j]);
            }
        }

        return dp[p][m];
    }
};

