const MOD = 1000000007

func modPow(base, exp, mod int64) int64 {
    result := int64(1)
    base %= mod
    for exp > 0 {
        if exp%2 == 1 {
            result = (result * base) % mod
        }
        base = (base * base) % mod
        exp /= 2
    }
    return result
}

func modInv(a, mod int64) int64 {
    return modPow(a, mod-2, mod)
}

func computeBinomial(n, k int) int64 {
    if k > n || k < 0 {
        return 0
    }
    if k == 0 || k == n {
        return 1
    }
    if k > n-k {
        k = n - k
    }

    num := int64(1)
    den := int64(1)

    for i := 0; i < k; i++ {
        num = (num * int64(n-i)) % MOD
        den = (den * int64(i+1)) % MOD
    }

    return (num * modInv(den, MOD)) % MOD
}

func solve(M, N, L int) int64 {
    total := M * N

    if L > total {
        return 0
    }

    binomCoeff := computeBinomial(total-2, L-2)

    rowSum := int64(0)
    for r1 := 0; r1 < M; r1++ {
        for r2 := r1 + 1; r2 < M; r2++ {
            dist := int64(r2 - r1)
            count := int64(N) * int64(N) % MOD
            contribution := (dist * count) % MOD
            contribution = (contribution * binomCoeff) % MOD
            rowSum = (rowSum + contribution) % MOD
        }
    }

    colSum := int64(0)
    for c1 := 0; c1 < N; c1++ {
        for c2 := c1 + 1; c2 < N; c2++ {
            dist := int64(c2 - c1)
            count := int64(M) * int64(M) % MOD
            contribution := (dist * count) % MOD
            contribution = (contribution * binomCoeff) % MOD
            colSum = (colSum + contribution) % MOD
        }
    }

    result := (rowSum + colSum) % MOD
    return result
}

func main() {
    var M, N, L int
    fmt.Scan(&M, &N, &L)

    result := solve(M, N, L)
    fmt.Println(result)
}

using namespace std;

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

long long nCr(int n, int r, const vector<long long>& fact, const vector<long long>& invFact) {
    if (r < 0 || r > n) return 0;
    return fact[n] * invFact[r] % 1000000007 * invFact[n - r] % 1000000007;
}

int main() {
    int M, N, L;
    if (!(cin >> M >> N >> L)) return 0;

    int totalCells = M * N;
    vector<long long> fact(totalCells + 1);
    vector<long long> invFact(totalCells + 1);
    fact[0] = 1;
    for (int i = 1; i <= totalCells; i++) fact[i] = (fact[i - 1] * i) % 1000000007;
    invFact[totalCells] = modInverse(fact[totalCells]);
    for (int i = totalCells - 1; i >= 0; i--) invFact[i] = (invFact[i + 1] * (i + 1)) % 1000000007;

    long long sumDist = 0;

    for (int d = 1; d < M; d++) {
        long long count = (long long)(M - d) * N % 1000000007 * N % 1000000007;
        sumDist = (sumDist + count * d) % 1000000007;
    }

    for (int d = 1; d < N; d++) {
        long long count = (long long)(N - d) * M % 1000000007 * M % 1000000007;
        sumDist = (sumDist + count * d) % 1000000007;
    }

    long long multiplier = nCr(totalCells - 2, L - 2, fact, invFact);
    long long result = (sumDist * multiplier) % 1000000007;

    cout << result << endl;

    return 0;
}

import java.util.Scanner;

public class Main {
    private static final long MOD = 1_000_000_000 + 7;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int M = sc.nextInt();
        int N = sc.nextInt();
        int L = sc.nextInt();
        System.out.println(solve(M, N, L));
    }

    private static long solve(int M, int N, int L) {
        long totalDist = 0;

        for (int d = 1; d < M; d++) {
            long ways = (long) d * (M - d) % MOD;
            ways = (ways * N) % MOD;
            ways = (ways * N) % MOD;
            totalDist = (totalDist + ways) % MOD;
        }

        for (int d = 1; d < N; d++) {
            long ways = (long) d * (N - d) % MOD;
            ways = (ways * M) % MOD;
            ways = (ways * M) % MOD;
            totalDist = (totalDist + ways) % MOD;
        }

        long combinations = nCr(M * N - 2, L - 2);
        return (totalDist * combinations) % MOD;
    }

    private static long nCr(int n, int r) {
        if (r < 0 || r > n) return 0;
        if (r == 0 || r == n) return 1;
        if (r > n / 2) r = n - r;

        long num = 1;
        long den = 1;
        for (int i = 0; i < r; i++) {
            num = (num * (n - i)) % MOD;
            den = (den * (i + 1)) % MOD;
        }
        return (num * power(den, MOD - 2)) % MOD;
    }

    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }
}

