class CodeSolver {
public:
    int compute_secure_codes(std::vector<int>& tiles) {
        std::set<int> unique_codes;
        int n = tiles.size();
        for (int i = 0; i < n; ++i) {
            if (tiles[i] == 0) continue;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                for (int k = 0; k < n; ++k) {
                    if (k == i || k == j) continue;
                    if (tiles[k] % 2 == 0) {
                        int code = tiles[i] * 100 + tiles[j] * 10 + tiles[k];
                        unique_codes.insert(code);
                    }
                }
            }
        }
        return unique_codes.size();
    }
};

