    vector<ll> M(N);
    for (int i = 0; i < N; ++i) {
        cin >> M[i];
    }

    set<ll> results;
    vector<int> partition(N);

    auto generate_partitions = [&](auto self, int idx, int count) {
        if (idx == N) {
            vector<ll> sums(count, 0);
            for (int i = 0; i < N; ++i) {
                sums[partition[i]] += M[i];
            }
            ll current_xor = 0;
            for (ll s : sums) {
                if (s > 0) current_xor ^= s;
            }
            results.insert(current_xor);
            return;
        }

        for (int i = 0; i < count; ++i) {
            partition[idx] = i;
            self(self, idx + 1, count);
        }
        partition[idx] = count;
        self(self, idx + 1, count + 1);
    };

    generate_partitions(generate_partitions, 0, 0);
    cout << results.size() << endl;
}

