    int cost1[3] = {r1.to1, r2.to1, r3.to1};

    int minTo0 = 1e9;
    minTo0 = min(minTo0, cost0[0] + cost0[1] + cost0[2]);
    minTo0 = min(minTo0, cost0[0] + cost0[1] + cost1[2]);
    minTo0 = min(minTo0, cost0[0] + cost1[1] + cost0[2]);
