public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int N = sc.nextInt();
        String D = sc.next();
        int totalLength = (int) Math.pow(3, N);
        int[] data = new int[totalLength];
        for (int i = 0; i < totalLength; i++) {
            data[i] = D.charAt(i) - '0';
        }

        int[][] dp = solve(data, 0, totalLength);
        int finalValue = getConsensus(data, 0, totalLength);

        if (finalValue == 0) {
            System.out.println(dp[1][0]);
        } else {
            System.out.println(dp[0][0]);
        }
    }

    private static int getConsensus(int[] data, int start, int length) {
        if (length == 1) return data[start];
        int subLen = length / 3;
        int v1 = getConsensus(data, start, subLen);
        int v2 = getConsensus(data, start + subLen, subLen);
        int v3 = getConsensus(data, start + 2 * subLen, subLen);
        return (v1 + v2 + v3 >= 2) ? 1 : 0;
    }

    private static int[][] solve(int[] data, int start, int length) {
        int[][] res = new int[2][1];
        if (length == 1) {
            res[0][0] = (data[start] == 0) ? 0 : 1;
            res[1][0] = (data[start] == 1) ? 0 : 1;
            return res;
        }

        int subLen = length / 3;
        int[][] left = solve(data, start, subLen);
        int[][] mid = solve(data, start + subLen, subLen);
        int[][] right = solve(data, start + 2 * subLen, subLen);

        int[] cost0 = new int[3];
        cost0[0] = left[0][0];
        cost0[1] = mid[0][0];
        cost0[2] = right[0][0];

        int[] cost1 = new int[3];
        cost1[1] = left[1][0];
        cost1[1] = mid[1][0];
        cost1[1] = right[1][0];

        int minTo0 = calculateMin(left[0][0], mid[0][0], right[0][0], left[1][0], mid[1][0], right[1][0], 0);
        int minTo1 = calculateMin(left[0][0], mid[0][0], right[0][0], left[1][0], mid[1][0], right[1][0], 1);

        res[0][0] = minTo0;
        res[1][0] = minTo1;
        return res;
    }

    private static int calculateMin(int l0, int m0, int r0, int l1, int m1, int r1, int target) {
        if (target == 0) {
            int c1 = l0 + m0 + r0;
            int c2 = l0 + m0 + r1;
            int c3 = l0 + m1 + r0;
            int c4 = l1 + m0 + r0;
            return Math.min(c1, Math.min(c2, Math.min(c3, c4)));
        } else {
            int c1 = l1 + m1 + r1;
            int c2 = l1 + m1 + r0;
            int c3 = l1 + m0 + r1;
            int c4 = l0 + m1 + r1;
            return Math.min(c1, Math.min(c2, Math.min(c3, c4)));
        }
    }
}

package main

import (
	"bufio"
	"container/heap"
	"fmt"
	"os"
	"sort"
)

type State struct {
	i, j, k int
	score   int64
}

type MaxHeap []State

func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return h[i].score > h[j].score }
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MaxHeap) Push(x interface{}) {
	*h = append(*h, x.(State))
}

func (h *MaxHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, k int
	fmt.Fscan(reader, &n, &k)

	x := make([]int64, n)
	y := make([]int64, n)
	z := make([]int64, n)

	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &x[i])
	}
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &y[i])
	}
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &z[i])
	}

	sort.Slice(x, func(i, j int) bool { return x[i] > x[j] })
	sort.Slice(y, func(i, j int) bool { return y[i] > y[j] })
	sort.Slice(z, func(i, j int) bool { return z[i] > z[j] })

	calcScore := func(i, j, k int) int64 {
		return x[i]*y[j] + y[j]*z[k] + z[k]*x[i]
	}

	h := &MaxHeap{}
	heap.Init(h)

	visited := make(map[[3]int]bool)

	initialScore := calcScore(0, 0, 0)
	heap.Push(h, State{0, 0, 0, initialScore})
	visited[[3]int{0, 0, 0}] = true

	var result int64

	for count := 0; count < k; count++ {
		current := heap.Pop(h).(State)
		result = current.score

		nextStates := [][3]int{
			{current.i + 1, current.j, current.k},
			{current.i, current.j + 1, current.k},
			{current.i, current.j, current.k + 1},
		}

		for _, next := range nextStates {
			if next[0] < n && next[1] < n && next[2] < n {
				key := [3]int{next[0], next[1], next[2]}
				if !visited[key] {
					visited[key] = true
					score := calcScore(next[0], next[1], next[2])
					heap.Push(h, State{next[0], next[1], next[2], score})
				}
			}
		}
	}

	fmt.Fprintln(writer, result)
}

