    };

    priority_queue<State> pq;
    pq.push({calc(0, 0, 0), 0, 0, 0});

    struct Triple {
        int i, j, k;
        bool operator<(const Triple& o) const {
            if (i != o.i) return i < o.i;
            if (j != o.j) return j < o.j;
            return k < o.k;
        }
        bool operator==(const Triple& o) const {
            return i == o.i && j == o.j && k == o.k;
        }
    };

    auto hash_triple = [](int i, int j, int k) {
        return (1LL * i * 10000000000LL) + (1LL * j * 100000LL) + k;
    };

    priority_queue<pair<long long, long long>> q;
    q.push({calc(0, 0, 0), hash_triple(0, 0, 0)});

    vector<long long> visited;
    visited.push_back(hash_triple(0, 0, 0));
    sort(visited.begin(), visited.end());

    for (int count = 1; count <= K; ++count) {
        pair<long long, long long> top = q.top();
        q.pop();

        if (count == K) {
            cout << top.first << endl;
            break;
        }

        long long h = top.second;
        int i = h / 10000000000LL;
        int j = (h / 100000LL) % 100000LL;
        int k = h % 100000LL;

        int di[] = {1, 0, 0};
        int dj[] = {0, 1, 0};
        int dk[] = {0, 0, 1};

        for (int d = 0; d < 3; ++d) {
            int ni = i + di[d], nj = j + dj[d], nk = k + dk[d];
            if (ni < N && nj < N && nk < N) {
                long long nh = hash_triple(ni, nj, nk);
                static vector<long long> seen;
                if (!binary_search(visited.begin(), visited.end(), nh)) {
                    visited.insert(lower_bound(visited.begin(), visited.end(), nh), nh);
                    q.push({calc(ni, nj, nk), nh});
                }
            }
        }
    }

    return 0;
}

