			wheels[i][symbol]++
		}
	}

	maxProb := 0.0

	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			prob := calculateProbability(wheels[i], wheels[j], sizes[i], sizes[j])
			if prob > maxProb {
				maxProb = prob
			}
		}
	}

	fmt.Printf("%.15f\n", maxProb)
