            sys.stdout.write(str(val) + '\n')
        return

    max_r = 0
    for x in r:
        if x > max_r:
            max_r = x

    count = [0] * (max_r + 1)
    for x in r:
        count[x] += 1

    div_count = [0] * (max_r + 1)
    for i in range(1, max_r + 1):
        for j in range(i, max_r + 1, i):
            div_count[i] += count[j]

    max_gcd_for_div = [0] * (max_r + 1)
    for i in range(max_r, 0, -1):
        if div_count[i] >= c:
            max_gcd_for_div[i] = i
        else:
            max_gcd_for_div[i] = 0

    ans_for_val = [1] * (max_r + 1)
    for i in range(max_r, 1, -1):
        if div_count[i] >= c:
            for j in range(i, max_r + 1, i):
                if ans_for_val[j] < i:
                    ans_for_val[j] = i

    output = []
