					}
				}
			}
		}
	}

	writer := bufio.NewWriter(os.Stdout)
	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			writer.WriteString(fmt.Sprintf("%d", dist[i][j]))
			if j < n-1 {
				writer.WriteByte(' ')
			}
		}
		writer.WriteByte('\n')
	}
	writer.Flush()
}

