	for i := 0; i < M; i++ {
		fmt.Scan(&tokens[i])
	}

	sort.Slice(relics, func(i, j int) bool {
		return relics[i] > relics[j]
	})

	sort.Slice(tokens, func(i, j int) bool {
		return tokens[i] > tokens[j]
	})

	relicPrefix := make([]int, N+1)
	for i := 0; i < N; i++ {
		relicPrefix[i+1] = relicPrefix[i] + relics[i]
	}

	tokenPrefix := make([]int, M+1)
	for i := 0; i < M; i++ {
		tokenPrefix[i+1] = tokenPrefix[i] + tokens[i]
	}

	maxVal := 0

	for k := 0; k <= M; k++ {
		tokenSum := tokenPrefix[k]

		for j := k; j <= N; j++ {
			relicSum := relicPrefix[j]
			total := relicSum + tokenSum
			if total > maxVal {
				maxVal = total
			}
		}
	}

	fmt.Println(maxVal)
