vector<pair<int, long long>> adj[11];
bool visited[11];
long long minXOR;

void dfs(int node, long long currentXOR) {
    if (node == N) {
        minXOR = min(minXOR, currentXOR);
        return;
    }

    for (auto &edge : adj[node]) {
        int next = edge.first;
        long long weight = edge.second;

        if (!visited[next]) {
            visited[next] = true;
            dfs(next, currentXOR ^ weight);
            visited[next] = false;
        }
    }
}

