    cin >> L >> M;

    vector<string> grid(L);
    for (int i = 0; i < L; i++) {
        cin >> grid[i];
    }

    int minSum = L * M;

    for (int colMask = 0; colMask < (1 << M); colMask++) {
        int currentSum = 0;

        for (int i = 0; i < L; i++) {
            int sumWithoutRowToggle = 0;
            for (int j = 0; j < M; j++) {
                int original = grid[i][j] - '0';
                int colToggle = (colMask >> j) & 1;
                sumWithoutRowToggle += (original ^ colToggle);
            }
            int sumWithRowToggle = M - sumWithoutRowToggle;
            currentSum += min(sumWithoutRowToggle, sumWithRowToggle);
        }

        minSum = min(minSum, currentSum);
    }

    cout << minSum << endl;

    return 0;
}

