        int M = sc.nextInt();
        sc.nextLine();

        int[][] grid = new int[L][M];
        for (int i = 0; i < L; i++) {
            String line = sc.nextLine();
            for (int j = 0; j < M; j++) {
                grid[i][j] = line.charAt(j) - '0';
            }
        }

        int minSum = Integer.MAX_VALUE;

        for (int colMask = 0; colMask < (1 << M); colMask++) {
            int currentSum = 0;

            for (int row = 0; row < L; row++) {
                int onesWithoutRowToggle = 0;
                int onesWithRowToggle = 0;

                for (int col = 0; col < M; col++) {
                    int value = grid[row][col];

                    if ((colMask & (1 << col)) != 0) {
                        value = 1 - value;
                    }

                    onesWithoutRowToggle += value;
                    onesWithRowToggle += (1 - value);
                }

                currentSum += Math.min(onesWithoutRowToggle, onesWithRowToggle);
            }

            minSum = Math.min(minSum, currentSum);
        }

        System.out.println(minSum);
        sc.close();
    }
