import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    N = int(input_data[0])
    K = int(input_data[1])

    if K == 1:
        print("Yes")
        return

    adj = [[] for _ in range(N * K + 1)]
    idx = 2
    for _ in range(N * K - 1):
        u = int(input_data[idx])
        v = int(input_data[idx+1])
        adj[u].append(v)
        adj[v].append(u)
        idx += 2

    sys.setrecursionlimit(300000)

    possible = True

    def dfs(u, p):
        nonlocal possible
        if not possible:
            return 0

        lengths = []
        for v in adj[u]:
            if v == p:
                continue
            res = dfs(v, u)
            if not possible:
                return 0
            if res > 0:
                lengths.append(res)

        if not lengths:
            return 1

        total_needed = K - 1
        lengths.sort(reverse=True)

        remaining = 0
        current_sum = 0

        filtered = []
        for l in lengths:
            if l == K:
                continue
            else:
                filtered.append(l)

        if not filtered:
            return 1

        if len(filtered) > 2:
            possible = False
            return 0

        if len(filtered) == 1:
            if filtered[0] + 1 <= K:
                return filtered[0] + 1
            else:
                possible = False
                return 0

        if len(filtered) == 2:
            if filtered[0] + filtered[1] + 1 == K:
                return K
            else:
                possible = False
                return 0

        return 1

    root_res = dfs(1, -1)

    if possible and (root_res == 1 or root_res == K):
        print("Yes")
    else:
        print("No")

