import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] p = new int[n];
        for (int i = 0; i < n; i++) {
            p[i] = sc.nextInt();
        }

        int[] prefixUnique = new int[n];
        int[] suffixUnique = new int[n];

        Set<Integer> seen = new HashSet<>();
        for (int i = 0; i < n; i++) {
            seen.add(p[i]);
            prefixUnique[i] = seen.size();
        }

        seen.clear();
        for (int i = n - 1; i >= 0; i--) {
            seen.add(p[i]);
            suffixUnique[i] = seen.size();
        }

        int maxSum = 0;

        for (int i = 0; i < n - 2; i++) {
            for (int j = i + 1; j < n - 1; j++) {
                int firstPart = prefixUnique[i];

                seen.clear();
                for (int k = i + 1; k <= j; k++) {
                    seen.add(p[k]);
                }
                int secondPart = seen.size();

                int thirdPart = suffixUnique[j + 1];

                int sum = firstPart + secondPart + thirdPart;
                maxSum = Math.max(maxSum, sum);
            }
        }

        System.out.println(maxSum);
    }
