string solve() {
    string s;
    if (!(cin >> s)) return "";
    int n = s.length();
    string rev_s = s;
    reverse(rev_s.begin(), rev_s.end());
    string combined = rev_s + "#" + s;
    int m = combined.length();
    vector<int> pi(m);
    for (int i = 1; i < m; i++) {
        int j = pi[i - 1];
        while (j > 0 && combined[i] != combined[j])
            j = pi[j - 1];
        if (combined[i] == combined[j])
            j++;
        pi[i] = j;
    }
    int longest_suffix_palindrome = pi[m - 1];
    string suffix_to_add = s.substr(0, n - longest_suffix_palindrome);
    reverse(suffix_to_add.begin(), suffix_to_add.end());
    return s + suffix_to_add;
}

