type DSU struct {
	parent []int
	rank   []int
}

func NewDSU(n int) *DSU {
	dsu := &DSU{
		parent: make([]int, n+1),
		rank:   make([]int, n+1),
	}
	for i := 0; i <= n; i++ {
		dsu.parent[i] = i
	}
	return dsu
}

func (dsu *DSU) Find(x int) int {
	if dsu.parent[x] != x {
		dsu.parent[x] = dsu.Find(dsu.parent[x])
	}
	return dsu.parent[x]
}

func (dsu *DSU) Union(x, y int) bool {
	px := dsu.Find(x)
	py := dsu.Find(y)
	if px == py {
		return false
	}
	if dsu.rank[px] < dsu.rank[py] {
		dsu.parent[px] = py
	} else if dsu.rank[px] > dsu.rank[py] {
		dsu.parent[py] = px
	} else {
		dsu.parent[py] = px
		dsu.rank[px]++
	}
	return true
}

