func abs(a int) int {
	if a < 0 {
		return -a
	}
	return a
}

func solve(n int, b []int) int {
	pos := make([][]int, n+1)
	for i := 1; i <= n; i++ {
		pos[i] = make([]int, 0, 2)
	}

	for i := 0; i < 2*n; i++ {
		pos[b[i]] = append(pos[b[i]], i)
	}

	count := 0

	for x := 1; x <= n; x++ {
		for y := x + 1; y <= n; y++ {
			x1, x2 := pos[x][0], pos[x][1]
			y1, y2 := pos[y][0], pos[y][1]

			if abs(x1-x2) == 1 || abs(y1-y2) == 1 {
				continue
			}

			if canPair(x1, x2, y1, y2) {
				count++
			}
		}
	}

	return count
}

func canPair(x1, x2, y1, y2 int) bool {
	states := make(map[[4]int]bool)
	queue := [][4]int{{x1, x2, y1, y2}}
	states[[4]int{x1, x2, y1, y2}] = true

	for len(queue) > 0 {
		state := queue[0]
		queue = queue[1:]

		sx1, sx2, sy1, sy2 := state[0], state[1], state[2], state[3]

		if abs(sx1-sx2) == 1 && abs(sy1-sy2) == 1 {
			return true
		}

		swaps := [][2]int{
			{sx1, sy1}, {sx1, sy2}, {sx2, sy1}, {sx2, sy2},
		}

		for _, swap := range swaps {
			nx1, nx2, ny1, ny2 := sx1, sx2, sy1, sy2

			if swap[0] == sx1 && swap[1] == sy1 {
				nx1, ny1 = sy1, sx1
			} else if swap[0] == sx1 && swap[1] == sy2 {
				nx1, ny2 = sy2, sx1
			} else if swap[0] == sx2 && swap[1] == sy1 {
				nx2, ny1 = sy1, sx2
			} else if swap[0] == sx2 && swap[1] == sy2 {
				nx2, ny2 = sy2, sx2
			}

			if nx1 > nx2 {
				nx1, nx2 = nx2, nx1
			}
			if ny1 > ny2 {
				ny1, ny2 = ny2, ny1
			}

			newState := [4]int{nx1, nx2, ny1, ny2}
			if !states[newState] {
				states[newState] = true
				queue = append(queue, newState)
			}
		}
	}

	return false
}

