func sieve(n int) []int {
	isPrime := make([]bool, n+1)
	for i := 2; i <= n; i++ {
		isPrime[i] = true
	}
	for i := 2; i*i <= n; i++ {
		if isPrime[i] {
			for j := i * i; j <= n; j += i {
				isPrime[j] = false
			}
		}
	}
	primes := []int{}
	for i := 2; i <= n; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}
	return primes
}

func main() {
	limit := int64(1000000000000)
	primes := sieve(1000000)

	medallions := make(map[int64]bool)

	for i := 0; i < len(primes); i++ {
		p := int64(primes[i])
		if p*p > limit {
			break
		}

		powersP := []int64{}
		pp := p * p
		for pp <= limit {
			powersP = append(powersP, pp)
			if pp > limit/(p*p) {
				break
			}
			pp = pp * p * p
		}

		for j := i + 1; j < len(primes); j++ {
