func canTransform(L, M string, N, X, Y int) bool {
	if L == M {
		return true
	}

	visited := make(map[string]bool)
	queue := []string{L}
	visited[L] = true

	for len(queue) > 0 {
		current := queue[0]
		queue = queue[1:]

		neighbors := getNeighbors(current, N, X, Y)
		for _, next := range neighbors {
			if next == M {
				return true
			}
			if !visited[next] {
				visited[next] = true
				queue = append(queue, next)
			}
		}
	}

	return false
}

func getNeighbors(s string, N, X, Y int) []string {
	var neighbors []string
	bytes := []byte(s)

	for i := 0; i <= N-(X+Y); i++ {
		if canApplyOperationA(bytes, i, X, Y) {
			newBytes := make([]byte, len(bytes))
			copy(newBytes, bytes)
			applyOperationA(newBytes, i, X, Y)
			neighbors = append(neighbors, string(newBytes))
		}

		if canApplyOperationB(bytes, i, X, Y) {
			newBytes := make([]byte, len(bytes))
			copy(newBytes, bytes)
			applyOperationB(newBytes, i, X, Y)
			neighbors = append(neighbors, string(newBytes))
		}
	}

	return neighbors
}

func canApplyOperationA(s []byte, i, X, Y int) bool {
	for j := 0; j < X; j++ {
		if s[i+j] != '0' {
			return false
		}
	}
	for j := 0; j < Y; j++ {
		if s[i+X+j] != '1' {
			return false
		}
	}
	return true
}

func applyOperationA(s []byte, i, X, Y int) {
	for j := 0; j < Y; j++ {
		s[i+j] = '1'
	}
	for j := 0; j < X; j++ {
		s[i+Y+j] = '0'
	}
}

func canApplyOperationB(s []byte, i, X, Y int) bool {
	for j := 0; j < Y; j++ {
		if s[i+j] != '1' {
			return false
		}
	}
	for j := 0; j < X; j++ {
		if s[i+Y+j] != '0' {
			return false
		}
	}
	return true
}

func applyOperationB(s []byte, i, X, Y int) {
	for j := 0; j < X; j++ {
		s[i+j] = '0'
	}
	for j := 0; j < Y; j++ {
		s[i+X+j] = '1'
	}
}

