class Solution:
    def optimalTreasure(self, grid: list[list[int]]) -> int:
        if not grid or not grid[0]:
            return 0
        m, n = len(grid), len(grid[0])
        dp = [[[float('-inf')] * 3 for _ in range(n)] for _ in range(m)]

        val = grid[0][0]
        if val >= 0:
            dp[0][0][0] = val
            dp[0][0][1] = val
            dp[0][0][2] = val
        else:
            dp[0][0][0] = val
            dp[0][0][1] = 0
            dp[0][0][2] = 0

        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue

                val = grid[i][j]
                prev_states = []
                if i > 0:
                    prev_states.append(dp[i-1][j])
                if j > 0:
                    prev_states.append(dp[i][j-1])

                for state in prev_states:
                    dp[i][j][0] = max(dp[i][j][0], state[0] + val)

                    if val < 0:
                        dp[i][j][1] = max(dp[i][j][1], state[0], state[1] + val)
                        dp[i][j][2] = max(dp[i][j][2], state[1], state[2] + val)
                    else:
                        dp[i][j][1] = max(dp[i][j][1], state[1] + val)
                        dp[i][j][2] = max(dp[i][j][2], state[2] + val)

        return max(dp[m-1][n-1])

