func solve() {
	reader := bufio.NewReader(os.Stdin)
	var hubsCount, allowance int

	line, _ := reader.ReadString('\n')
	fmt.Sscanf(line, "%d %d", &hubsCount, &allowance)

	var connections [][]int
	decoder := json.NewDecoder(reader)
	if err := decoder.Decode(&connections); err != nil {
		return
	}

	costs := make([]int, 0, len(connections))
	for _, conn := range connections {
		costs = append(costs, conn[2])
	}
	sort.Ints(costs)

	uniqueCosts := make([]int, 0)
	if len(costs) > 0 {
		uniqueCosts = append(uniqueCosts, costs[0])
		for i := 1; i < len(costs); i++ {
			if costs[i] != costs[i-1] {
				uniqueCosts = append(uniqueCosts, costs[i])
			}
		}
	}

	check := func(maxCost int) bool {
		adj := make([][]int, hubsCount)
		for _, conn := range connections {
			if conn[2] <= maxCost {
				adj[conn[1]] = append(adj[conn[1]], conn[0])
			}
		}

		visited := make([]bool, hubsCount)
		queue := make([]int, 0, hubsCount)

		visited[0] = true
		queue = append(queue, 0)

		count := 1
		head := 0
		for head < len(queue) {
			u := queue[head]
			head++
			for _, v := range adj[u] {
				if !visited[v] {
					visited[v] = true
					count++
					queue = append(queue, v)
				}
			}
		}
		return count == hubsCount
	}

	ans := -1
	low := 0
	high := len(uniqueCosts) - 1
	for low <= high {
		mid := low + (high-low)/2
		if check(uniqueCosts[mid]) {
			ans = uniqueCosts[mid]
			high = mid - 1
		} else {
			low = mid + 1
		}
	}

	fmt.Println(ans)
}

