class Solution:
    def maxGameSegmentsSum(self, scores: list[int], p: int, n: int) -> int:
        length = len(scores)
        prefix_sum = [0] * (length + 1)
        for i in range(length):
            prefix_sum[i + 1] = prefix_sum[i] + scores[i]

        dp = [[-float('inf')] * (p + 1) for _ in range(length + 1)]
        for i in range(length + 1):
            dp[i][0] = 0

        for k in range(1, p + 1):
            best_prev_dp = -float('inf')
            for i in range(n * k, length + 1):
                best_prev_dp = max(best_prev_dp, dp[i - n][k - 1] - prefix_sum[i - n])
                dp[i][k] = max(dp[i - 1][k], prefix_sum[i] + best_prev_dp)

        return dp[length][p]

