class Solution:
    def aggregatePeakScores(self, scoreList: List[int], d: int) -> int:
        total = 0
        n = len(scoreList)

        for i in range(n):
            left_valid = (i - d) >= 0
            right_valid = (i + d) < n

            if left_valid and right_valid:
                if scoreList[i] > scoreList[i - d] and scoreList[i] > scoreList[i + d]:
                    total += scoreList[i]
            elif left_valid:
                if scoreList[i] > scoreList[i - d]:
                    total += scoreList[i]
            elif right_valid:
                if scoreList[i] > scoreList[i + d]:
                    total += scoreList[i]
            else:
                total += scoreList[i]

        return total

