	}

	minY := math.MaxFloat64
	maxY := -math.MaxFloat64
	totalArea := 0.0

	for _, f := range fields {
		y := float64(f[1])
		s := float64(f[2])
		if y < minY {
			minY = y
		}
		if y+s > maxY {
			maxY = y+s
		}
		totalArea += s * s
	}

	target := totalArea / 2.0
	low := minY
	high := maxY

	for i := 0; i < 100; i++ {
		mid := (low + high) / 2.0
		areaBelow := 0.0
		for _, f := range fields {
			y := float64(f[1])
			s := float64(f[2])
			side := float64(f[2])

			if mid <= y {
				areaBelow += 0
			} else if mid >= y+s {
				areaBelow += side * side
			} else {
				areaBelow += side * (mid - y)
			}
		}

		if areaBelow < target {
			low = mid
		} else {
			high = mid
		}
	}

