            current = majority(v0, v1, v2)

            costs = []

            flip0 = c0
            flip1 = c1
            flip2 = c2

            new_v0 = 1 - v0
            new_v1 = 1 - v1
            new_v2 = 1 - v2

            if majority(new_v0, v1, v2) != current:
