func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)

	if n < 4 {
		fmt.Println("-1")
		return
	}

	adj := make([][]int, n+1)
	for i := 0; i < n-1; i++ {
		var u, v int
		fmt.Fscan(reader, &u, &v)
		adj[u] = append(adj[u], v)
		adj[v] = append(adj[v], u)
	}

	dp := make([]int, n+1)
	ans := -1

	var dfs func(u, p int)
	dfs = func(u, p int) {
		children := make([]int, 0)
		for _, v := range adj[u] {
			if v == p {
				continue
			}
			dfs(v, u)
			if dp[v] != -1 {
				children = append(children, dp[v])
			}
		}

		if len(children) >= 3 {
			top3 := getTopK(children, 3)
			dp[u] = top3[0] + top3[1] + top3[2] + 1
		} else {
			dp[u] = 1
		}

		if len(adj[u]) >= 4 {
			allVals := make([]int, 0)
			for _, v := range adj[u] {
				if v == p {
					continue
				}
				if dp[v] != -1 {
					allVals = append(allVals, dp[v])
				}
			}

			if p != 0 {
				upVal := getUpValue(u, p, adj, dp)
				if upVal != -1 {
					allVals = append(allVals, upVal)
				}
			}

			if len(allVals) >= 4 {
				top4 := getTopK(allVals, 4)
				sum := top4[0] + top4[1] + top4[2] + top4[3] + 1
				if sum > ans {
					ans = sum
				}
			}
		}
	}

	dfs(1, 0)
	fmt.Println(ans)
}

func getTopK(arr []int, k int) []int {
	res := make([]int, k)
	for i := range res {
		res[i] = -1
	}
	for _, v := range arr {
		for i := 0; i < k; i++ {
			if v > res[i] {
				for j := k - 1; j > i; j-- {
					res[j] = res[j-1]
				}
				res[i] = v
				break
			}
		}
	}
	return res
}

func getUpValue(u, p int, adj [][]int, dp []int) int {
	siblings := make([]int, 0)
	for _, v := range adj[p] {
		if v == u {
			continue
		}
		if dp[v] != -1 {
			siblings = append(siblings, dp[v])
		}
	}

	parentCount := len(adj[p])
	if parentCount < 4 {
		return 1
	}

	top3 := getTopK(siblings, 3)
	if top3[2] == -1 {
		return 1
	}
	return top3[0] + top3[1] + top3[2] + 1
}

