const MOD = 1000000007

func modPow(base, exp, mod int64) int64 {
    result := int64(1)
    base %= mod
    for exp > 0 {
        if exp%2 == 1 {
            result = (result * base) % mod
        }
        base = (base * base) % mod
        exp /= 2
    }
    return result
}

func modInv(a, mod int64) int64 {
    return modPow(a, mod-2, mod)
}

func computeBinomial(n, k int) int64 {
    if k > n || k < 0 {
        return 0
    }
    if k == 0 || k == n {
        return 1
    }
    if k > n-k {
        k = n - k
    }

    num := int64(1)
    den := int64(1)

    for i := 0; i < k; i++ {
        num = (num * int64(n-i)) % MOD
        den = (den * int64(i+1)) % MOD
    }

    return (num * modInv(den, MOD)) % MOD
}

func solve(M, N, L int) int64 {
    total := M * N

    if L > total {
        return 0
    }

    binomCoeff := computeBinomial(total-2, L-2)

    rowSum := int64(0)
    for r1 := 0; r1 < M; r1++ {
        for r2 := r1 + 1; r2 < M; r2++ {
            dist := int64(r2 - r1)
            count := int64(N) * int64(N) % MOD
            contribution := (dist * count) % MOD
            contribution = (contribution * binomCoeff) % MOD
            rowSum = (rowSum + contribution) % MOD
        }
    }

    colSum := int64(0)
    for c1 := 0; c1 < N; c1++ {
        for c2 := c1 + 1; c2 < N; c2++ {
            dist := int64(c2 - c1)
            count := int64(M) * int64(M) % MOD
            contribution := (dist * count) % MOD
            contribution = (contribution * binomCoeff) % MOD
            colSum = (colSum + contribution) % MOD
        }
    }

    result := (rowSum + colSum) % MOD
    return result
}

