using namespace std;

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

long long nCr(int n, int r, const vector<long long>& fact, const vector<long long>& invFact) {
    if (r < 0 || r > n) return 0;
    return fact[n] * invFact[r] % 1000000007 * invFact[n - r] % 1000000007;
}

int main() {
    int M, N, L;
    if (!(cin >> M >> N >> L)) return 0;

    int totalCells = M * N;
    vector<long long> fact(totalCells + 1);
    vector<long long> invFact(totalCells + 1);
    fact[0] = 1;
    for (int i = 1; i <= totalCells; i++) fact[i] = (fact[i - 1] * i) % 1000000007;
    invFact[totalCells] = modInverse(fact[totalCells]);
    for (int i = totalCells - 1; i >= 0; i--) invFact[i] = (invFact[i + 1] * (i + 1)) % 1000000007;

    long long sumDist = 0;

    for (int d = 1; d < M; d++) {
        long long count = (long long)(M - d) * N % 1000000007 * N % 1000000007;
        sumDist = (sumDist + count * d) % 1000000007;
    }

    for (int d = 1; d < N; d++) {
        long long count = (long long)(N - d) * M % 1000000007 * M % 1000000007;
        sumDist = (sumDist + count * d) % 1000000007;
    }

    long long multiplier = nCr(totalCells - 2, L - 2, fact, invFact);
    long long result = (sumDist * multiplier) % 1000000007;

    cout << result << endl;

    return 0;
}

