        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int M = sc.nextInt();
        int N = sc.nextInt();
        int L = sc.nextInt();
        System.out.println(solve(M, N, L));
    }

    private static long solve(int M, int N, int L) {
        long totalDist = 0;

        for (int d = 1; d < M; d++) {
            long ways = (long) d * (M - d) % MOD;
            ways = (ways * N) % MOD;
            ways = (ways * N) % MOD;
            totalDist = (totalDist + ways) % MOD;
        }

        for (int d = 1; d < N; d++) {
            long ways = (long) d * (N - d) % MOD;
            ways = (ways * M) % MOD;
            ways = (ways * M) % MOD;
            totalDist = (totalDist + ways) % MOD;
        }

        long combinations = nCr(M * N - 2, L - 2);
        return (totalDist * combinations) % MOD;
    }

    private static long nCr(int n, int r) {
        if (r < 0 || r > n) return 0;
        if (r == 0 || r == n) return 1;
        if (r > n / 2) r = n - r;

        long num = 1;
        long den = 1;
        for (int i = 0; i < r; i++) {
            num = (num * (n - i)) % MOD;
            den = (den * (i + 1)) % MOD;
        }
        return (num * power(den, MOD - 2)) % MOD;
    }

    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }
}

