class Solution {
public:
    int highestOccurrence(vector<int>& scores, int target) {
        int n = scores.size();
        int base_count = 0;
        for (int s : scores) {
            if (s == target) base_count++;
        }

        int max_extra = 0;
        for (int v = 1; v <= 50; ++v) {
            if (v == target) continue;
            int current_extra = 0;
            int best_so_far = 0;
            for (int s : scores) {
                if (s == v) {
                    current_extra++;
                } else if (s == target) {
                    current_extra--;
                }
                if (current_extra < 0) current_extra = 0;
                if (current_extra > best_so_far) best_so_far = current_extra;
            }
            if (best_so_far > max_extra) max_extra = best_so_far;
        }

        return base_count + max_extra;
    }
};

