        std::cin >> D[i];
    }

    int left = 0;
    int right = N / 2;
    int ans = 0;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (mid == 0) {
            ans = std::max(ans, 0);
            left = mid + 1;
            continue;
        }

        bool possible = true;
        for (int i = 0; i < mid; ++i) {
            if (D[i] * 2 > D[N - mid + i]) {
                possible = false;
                break;
            }
        }

        if (possible) {
            ans = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

