        if (d[start] == '0') {
            return {0, 1};
        } else {
            return {1, 0};
        }
    }

    int power3 = 1;
    for (int i = 0; i < n - 1; ++i) power3 *= 3;

    Result r1 = solve(n - 1, d, start);
    Result r2 = solve(n - 1, d, start + power3);
    Result r3 = solve(n - 1, d, start + 2 * power3);

    int cost0[3] = {r1.to0, r2.to0, r3.to0};
    int cost1[3] = {r1.to1, r2.to1, r3.to1};

    int minTo0 = 1e9;
    minTo0 = min(minTo0, cost0[0] + cost0[1] + cost0[2]);
    minTo0 = min(minTo0, cost0[0] + cost0[1] + cost1[2]);
    minTo0 = min(minTo0, cost0[0] + cost1[1] + cost0[2]);
    minTo0 = min(minTo0, cost1[0] + cost0[1] + cost0[2]);

    int minTo1 = 1e9;
    minTo1 = min(minTo1, cost1[0] + cost1[1] + cost1[2]);
    minTo1 = min(minTo1, cost1[0] + cost1[1] + cost0[2]);
    minTo1 = min(minTo1, cost1[0] + cost0[1] + cost1[2]);
    minTo1 = min(minTo1, cost0[0] + cost1[1] + cost1[2]);

    return {minTo0, minTo1};
}

