func getDivisors(n int) []int {
	divisors := []int{}
	for i := 1; i*i <= n; i++ {
		if n%i == 0 {
			divisors = append(divisors, i)
			if i != n/i {
				divisors = append(divisors, n/i)
			}
		}
	}
	sort.Sort(sort.Reverse(sort.IntSlice(divisors)))
	return divisors
}

