public class Main {
    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int n = fr.nextInt();
        int c = fr.nextInt();
        int[] r = new int[n];
        int maxR = 0;
        for (int i = 0; i < n; i++) {
            r[i] = fr.nextInt();
            if (r[i] > maxR) maxR = r[i];
        }

        int[] freq = new int[maxR + 1];
        for (int x : r) {
            freq[x]++;
        }

        int[] countMultiples = new int[maxR + 1];
        for (int i = 1; i <= maxR; i++) {
            for (int j = i; j <= maxR; j += i) {
                countMultiples[i] += freq[j];
            }
        }

        int[] maxGcdForVal = new int[maxR + 1];
        for (int g = maxR; g >= 1; g--) {
            if (countMultiples[g] >= c) {
                for (int j = g; j <= maxR; j += g) {
                    if (maxGcdForVal[j] == 0) {
                        maxGcdForVal[j] = g;
                    }
                }
            }
        }

        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        for (int i = 0; i < n; i++) {
            out.println(maxGcdForVal[r[i]]);
        }
        out.flush();
        out.close();
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 16];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean fillBuffer() throws IOException {
            pointer = 0;
            bufferLength = in.read(buffer);
            return bufferLength > 0;
        }

        private byte read() throws IOException {
            if (pointer >= bufferLength) {
                if (!fillBuffer()) return -1;
            }
            return buffer[pointer++];
        }

        public int nextInt() throws IOException {
            int c = read();
            while (c >= 0 && c <= 32) c = read();
            if (c == -1) return -1;
            int res = 0;
            while (c > 32) {
                res = res * 10 + (c - '0');
                c = read();
            }
            return res;
        }
    }
}

import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    c = int(input_data[1])
    r = [int(x) for x in input_data[2:]]

    if c == 1:
        for val in r:
            sys.stdout.write(str(val) + '\n')
        return

    max_r = 0
    for x in r:
        if x > max_r:
            max_r = x

    count = [0] * (max_r + 1)
    for x in r:
        count[x] += 1

    div_count = [0] * (max_r + 1)
    for i in range(1, max_r + 1):
        for j in range(i, max_r + 1, i):
            div_count[i] += count[j]

    max_gcd_for_div = [0] * (max_r + 1)
    for i in range(max_r, 0, -1):
        if div_count[i] >= c:
            max_gcd_for_div[i] = i
        else:
            max_gcd_for_div[i] = 0

    ans_for_val = [1] * (max_r + 1)
    for i in range(max_r, 1, -1):
        if div_count[i] >= c:
            for j in range(i, max_r + 1, i):
                if ans_for_val[j] < i:
                    ans_for_val[j] = i

    output = []
    for x in r:
        output.append(str(ans_for_val[x]))
    sys.stdout.write('\n'.join(output) + '\n')

