func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, q int
	fmt.Fscan(reader, &n, &q)

	relics := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &relics[i])
	}

	for i := 0; i < q; i++ {
		var k, t int
		fmt.Fscan(reader, &k, &t)

		filtered := make([]int, 0)
		for j := 0; j < k; j++ {
			if relics[j] <= t {
				filtered = append(filtered, relics[j])
			}
		}

		lisLength := findLIS(filtered)
		fmt.Fprintln(writer, lisLength)
	}
}

func findLIS(arr []int) int {
	if len(arr) == 0 {
		return 0
	}

	tails := make([]int, 0)

	for _, num := range arr {
		pos := sort.Search(len(tails), func(i int) bool {
			return tails[i] >= num
		})

		if pos == len(tails) {
			tails = append(tails, num)
		} else {
			tails[pos] = num
		}
	}

	return len(tails)
}

