const int INF = 1e9 + 7;

struct Query {
    int k, t, id;
};

bool compareQueries(const Query& a, const Query& b) {
    return a.k < b.k;
}

struct Node {
    int val;
};

int tree_size;
vector<int> tree;

void update(int idx, int val) {
    idx += tree_size;
    if (tree[idx] >= val) return;
    tree[idx] = val;
    for (idx >>= 1; idx >= 1; idx >>= 1) {
        tree[idx] = max(tree[idx << 1], tree[idx << 1 | 1]);
    }
}

int query_max(int l, int r) {
    int res = 0;
    for (l += tree_size, r += tree_size; l < r; l >>= 1, r >>= 1) {
        if (l & 1) res = max(res, tree[l++]);
        if (r & 1) res = max(res, tree[--r]);
    }
    return res;
}

