    for (int i = 0; i < n; ++i) {
        cin >> r[i];
        coords.push_back(r[i]);
    }

    vector<Query> queries(q);
    for (int i = 0; i < q; ++i) {
        cin >> queries[i].k >> queries[i].t;
        queries[i].id = i;
        coords.push_back(queries[i].t);
    }

    sort(coords.begin(), coords.end());
    coords.erase(unique(coords.begin(), coords.end()), coords.end());

    auto get_coord = [&](int val) {
        return lower_bound(coords.begin(), coords.end(), val) - coords.begin();
    };

    sort(queries.begin(), queries.end(), compareQueries);

    tree_size = 1;
    while (tree_size < (int)coords.size()) tree_size <<= 1;
    tree.assign(2 * tree_size, 0);

    vector<int> results(q);
    int current_k = 0;
    for (int i = 0; i < q; ++i) {
        while (current_k < queries[i].k) {
            int val = r[current_k];
            int pos = get_coord(val);
            int max_prev = query_max(0, pos);
            update(pos, max_prev + 1);
            current_k++;
        }
        results[queries[i].id] = query_max(0, get_coord(queries[i].t) + 1);
    }

    for (int i = 0; i < q; ++i) {
        cout << results[i] << "\n";
    }

    return 0;
}

