int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    if (!(cin >> N)) return 0;

    vector<string> S(N);
    for (int i = 0; i < N; ++i) {
        cin >> S[i];
    }

    vector<vector<int>> dist(N, vector<int>(N, -1));
    queue<pair<int, int>> q;

    for (int i = 0; i < N; ++i) {
        dist[i][i] = 0;
        q.push({i, i});
    }

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            if (i != j && S[i][j] != '-') {
                if (dist[i][j] == -1) {
                    dist[i][j] = 1;
                    q.push({i, j});
                }
            }
        }
    }

    vector<vector<pair<int, int>>> adj(26);
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            if (S[i][j] != '-') {
                adj[S[i][j] - 'a'].push_back({i, j});
            }
        }
    }

    vector<vector<vector<int>>> in_nodes(26, vector<vector<int>>(N));
    vector<vector<vector<int>>> out_nodes(26, vector<vector<int>>(N));

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            if (S[i][j] != '-') {
                int c = S[i][j] - 'a';
                out_nodes[c][i].push_back(j);
                in_nodes[c][j].push_back(i);
            }
        }
    }

    while (!q.empty()) {
        pair<int, int> curr = q.front();
        q.pop();
        int u = curr.first;
        int v = curr.second;

        for (int c = 0; c < 26; ++c) {
            for (int prev_u : in_nodes[c][u]) {
                for (int next_v : out_nodes[c][v]) {
                    if (dist[prev_u][next_v] == -1) {
                        dist[prev_u][next_v] = dist[u][v] + 2;
                        q.push({prev_u, next_v});
                    }
                }
            }
        }
    }

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            cout << dist[i][j] << (j == N - 1 ? "" : " ");
        }
        cout << "\n";
    }

    return 0;
}

