func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscanf(reader, "%d\n", &n)

	s := make([]string, n)
	for i := 0; i < n; i++ {
		line, _ := reader.ReadString('\n')
		for len(line) > 0 && (line[len(line)-1] == '\n' || line[len(line)-1] == '\r') {
			line = line[:len(line)-1]
		}
		s[i] = line
	}

	ans := make([][]int, n)
	for i := range ans {
		ans[i] = make([]int, n)
		for j := range ans[i] {
			ans[i][j] = -1
		}
	}

	type state struct {
		u, v int
	}

	dist := make([][]int, n)
	for i := range dist {
		dist[i] = make([]int, n)
		for j := range dist[i] {
			dist[i][j] = -1
		}
	}

	queue := make([]state, 0, n*n)

	for i := 0; i < n; i++ {
		dist[i][i] = 0
		queue = append(queue, state{i, i})
	}

	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			if i != j && s[i][j] != '-' {
				if dist[i][j] == -1 {
					dist[i][j] = 1
					queue = append(queue, state{i, j})
				}
			}
		}
	}

	head := 0
	for head < len(queue) {
		curr := queue[head]
		head++

		u, v := curr.u, curr.v

		for i := 0; i < n; i++ {
			if s[i][u] == '-' {
				continue
			}
			for j := 0; j < n; j++ {
				if s[v][j] == '-' {
					continue
				}
				if s[i][u] == s[v][j] {
					if dist[i][j] == -1 {
						dist[i][j] = dist[u][v] + 2
						queue = append(queue, state{i, j})
					}
				}
			}
		}
	}

	writer := bufio.NewWriter(os.Stdout)
	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			writer.WriteString(fmt.Sprintf("%d", dist[i][j]))
			if j < n-1 {
				writer.WriteByte(' ')
			}
		}
		writer.WriteByte('\n')
	}
	writer.Flush()
}

