import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int n = fr.nextInt();
        int[] p = new int[n];
        for (int i = 0; i < n; i++) {
            p[i] = fr.nextInt();
        }

        int[] leftDistinct = new int[n];
        boolean[] seenLeft = new boolean[n + 1];
        int currentLeft = 0;
        for (int i = 0; i < n; i++) {
            if (!seenLeft[p[i]]) {
                seenLeft[p[i]] = true;
                currentLeft++;
            }
            leftDistinct[i] = currentLeft;
        }

        int[] rightDistinct = new int[n];
        boolean[] seenRight = new boolean[n + 1];
        int currentRight = 0;
        for (int i = n - 1; i >= 0; i--) {
            if (!seenRight[p[i]]) {
                seenRight[p[i]] = true;
                currentRight++;
            }
            rightDistinct[i] = currentRight;
        }

        int maxTotal = 0;
        for (int i = 0; i < n - 1; i++) {
            int total = leftDistinct[i] + rightDistinct[i + 1];
            if (total > maxTotal) {
                maxTotal = total;
            }
        }

        System.out.println(maxTotal);
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 16];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean fillBuffer() throws IOException {
            bufferLength = in.read(buffer);
            pointer = 0;
            return bufferLength > 0;
        }

        private byte read() throws IOException {
            if (pointer >= bufferLength) {
                if (!fillBuffer()) return -1;
            }
            return buffer[pointer++];
        }

        public int nextInt() throws IOException {
            int c = read();
            while (c >= 0 && c <= 32) c = read();
            if (c == -1) return -1;
            int neg = 1;
            if (c == '-') {
                neg = -1;
                c = read();
            }
            int res = 0;
            while (c >= '0' && c <= '9') {
                res = res * 10 + (c - '0');
                c = read();
            }
            return res * neg;
        }
    }
}

