import (
	"bufio"
	"fmt"
	"os"
)

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var N, K int
	fmt.Fscanf(reader, "%d %d\n", &N, &K)

	totalNodes := N * K
	adj := make([][]int, totalNodes+1)

	for i := 0; i < totalNodes-1; i++ {
		var a, b int
		fmt.Fscanf(reader, "%d %d\n", &a, &b)
		adj[a] = append(adj[a], b)
		adj[b] = append(adj[b], a)
	}

	used := make([]bool, totalNodes+1)
	pathCount := 0

	var dfs func(node, parent, depth int) int
	dfs = func(node, parent, depth int) int {
		if used[node] {
			return 0
		}

		if depth == K {
			return K
		}

		for _, next := range adj[node] {
			if next == parent || used[next] {
				continue
			}
			result := dfs(next, node, depth+1)
			if result == K {
				return K
			}
		}

		return depth
	}

	var buildPath func(node, parent, depth int) bool
	buildPath = func(node, parent, depth int) bool {
		if used[node] {
			return false
		}

		used[node] = true

		if depth == K {
			return true
		}

		for _, next := range adj[node] {
			if next == parent || used[next] {
				continue
			}
			if buildPath(next, node, depth+1) {
				return true
			}
		}

		used[node] = false
		return false
	}

	for start := 1; start <= totalNodes; start++ {
		if used[start] {
			continue
		}

		if buildPath(start, -1, 1) {
			pathCount++
		} else {
			for i := 1; i <= totalNodes; i++ {
				used[i] = false
			}
			break
		}
	}

	if pathCount == N {
		fmt.Fprintln(writer, "Yes")
	} else {
		fmt.Fprintln(writer, "No")
	}
}

using namespace std;

int N, K;
vector<vector<int>> adj;
bool possible = true;

int dfs(int u, int p) {
    if (!possible) return 0;

    vector<int> children_rem;
    for (int v : adj[u]) {
        if (v == p) continue;
        int rem = dfs(v, u);
        if (rem > 0) {
            children_rem.push_back(rem);
        }
    }

    if (!possible) return 0;

    if (K == 1) return 0;

    int total_needed = K - 1;
    sort(children_rem.begin(), children_rem.end());

    vector<int> unpaired;
    int i = 0, j = (int)children_rem.size() - 1;
    while (i <= j) {
        if (i == j) {
            unpaired.push_back(children_rem[i]);
            break;
        }
        if (children_rem[i] + children_rem[j] == total_needed) {
            i++;
            j--;
        } else if (children_rem[i] + children_rem[j] < total_needed) {
            unpaired.push_back(children_rem[i]);
            i++;
        } else {
            unpaired.push_back(children_rem[j]);
            j--;
        }
    }

    if (unpaired.size() > 1) {
        possible = false;
        return 0;
    }

    if (unpaired.empty()) {
        return 1;
    } else {
        int res = unpaired[0] + 1;
        if (res == K) return 0;
        return res;
    }
}

