using namespace std;

bool isHarmonicEnsemble(vector<int>& selection) {
    map<int, int> freq;
    for (int val : selection) {
        freq[val]++;
    }

    if (freq.size() != 2) return false;

    vector<int> counts;
    for (auto& p : freq) {
        counts.push_back(p.second);
    }

    sort(counts.begin(), counts.end());
    return (counts[0] == 2 && counts[1] == 3);
}

bool canFormHarmonic(vector<int>& instruments) {
    int n = instruments.size();

    for (int mask = 0; mask < (1 << n); mask++) {
        if (__builtin_popcount(mask) == 5) {
            vector<int> selection;
            for (int i = 0; i < n; i++) {
                if (mask & (1 << i)) {
                    selection.push_back(instruments[i]);
                }
            }
            if (isHarmonicEnsemble(selection)) {
                return true;
            }
        }
    }

    return false;
}

