import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String prefix = sc.nextLine();
        sc.close();

        String result = findMinimalPalindrome(prefix);
        System.out.println(result);
    }

    static String findMinimalPalindrome(String s) {
        int n = s.length();

        for (int i = 0; i < n; i++) {
            if (isPalindrome(s, i)) {
                StringBuilder sb = new StringBuilder(s);
                for (int j = i - 1; j >= 0; j--) {
                    sb.append(s.charAt(j));
                }
                return sb.toString();
            }
        }

        return s;
    }

    static boolean isPalindrome(String s, int start) {
        int left = start;
        int right = s.length() - 1;

        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }

        return true;
    }
}

using namespace std;

string solve() {
    string s;
    if (!(cin >> s)) return "";
    int n = s.length();
    string rev_s = s;
    reverse(rev_s.begin(), rev_s.end());
    string combined = rev_s + "#" + s;
    int m = combined.length();
    vector<int> pi(m);
    for (int i = 1; i < m; i++) {
        int j = pi[i - 1];
        while (j > 0 && combined[i] != combined[j])
            j = pi[j - 1];
        if (combined[i] == combined[j])
            j++;
        pi[i] = j;
    }
    int longest_suffix_palindrome = pi[m - 1];
    string suffix_to_add = s.substr(0, n - longest_suffix_palindrome);
    reverse(suffix_to_add.begin(), suffix_to_add.end());
    return s + suffix_to_add;
}

