	fmt.Scan(&n, &m)

	dsu := NewDSU(n)

	for i := 0; i < m; i++ {
		var a, b int
		fmt.Scan(&a, &b)
		dsu.Union(a, b)
	}

	components := 0
	for i := 1; i <= n; i++ {
		if dsu.Find(i) == i {
			components++
		}
	}

	maxEdges := n - components
	result := m - maxEdges

	fmt.Println(result)
