func sieve(n int) []int {
	isPrime := make([]bool, n+1)
	for i := 2; i <= n; i++ {
		isPrime[i] = true
	}
	for i := 2; i*i <= n; i++ {
		if isPrime[i] {
			for j := i * i; j <= n; j += i {
				isPrime[j] = false
			}
		}
	}
	primes := []int{}
	for i := 2; i <= n; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}
	return primes
}

func main() {
	limit := int64(1000000000000)
	primes := sieve(1000000)

	medallions := make(map[int64]bool)

	for i := 0; i < len(primes); i++ {
		p := int64(primes[i])
		if p*p > limit {
			break
		}

		powersP := []int64{}
		pp := p * p
		for pp <= limit {
			powersP = append(powersP, pp)
			if pp > limit/(p*p) {
				break
			}
			pp = pp * p * p
		}

		for j := i + 1; j < len(primes); j++ {
			q := int64(primes[j])
			if q*q > limit {
				break
			}

			for _, pPow := range powersP {
				qq := q * q
				for qq <= limit/pPow {
					medallions[pPow*qq] = true
					if qq > limit/(q*q) {
						break
					}
					qq = qq * q * q
				}
			}
		}
	}

	sorted := make([]int64, 0, len(medallions))
	for m := range medallions {
		sorted = append(sorted, m)
	}
	sort.Slice(sorted, func(i, j int) bool {
		return sorted[i] < sorted[j]
	})

	var Q int
	fmt.Scan(&Q)

	for i := 0; i < Q; i++ {
		var B int64
		fmt.Scan(&B)

		idx := sort.Search(len(sorted), func(k int) bool {
			return sorted[k] > B
		})
		fmt.Println(sorted[idx-1])
	}
}

