public class Main {
    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int n = fr.nextInt();
        long[] p = new long[n];
        for (int i = 0; i < n; i++) {
            p[i] = fr.nextLong();
        }

        long[] dp = new long[n + 1];
        Arrays.fill(dp, Long.MIN_VALUE / 2);
        dp[0] = 0;

        Deque<Integer> deque = new ArrayDeque<>();
        deque.add(0);

        for (int i = 1; i <= n; i++) {
            long currentP = p[i - 1];
            long opt1 = dp[i - 1] + currentP;
            long opt2 = Long.MIN_VALUE / 2;

            if (i >= 2) {
                opt2 = dp[i - 2];
            }

            dp[i] = Math.max(opt1, opt2);
        }

        System.out.println(dp[n]);
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (pointer < bufferLength) return true;
            pointer = 0;
            try {
                bufferLength = in.read(buffer);
            } catch (IOException e) {
                return false;
            }
            return bufferLength > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[pointer++] : -1;
        }

        public int nextInt() {
            return (int) nextLong();
        }

        public long nextLong() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            if (b == -1) return 0;
            boolean negative = false;
            if (b == '-') {
                negative = true;
                b = readByte();
            }
            long res = 0;
            while (b >= '0' && b <= '9') {
                res = res * 10 + (b - '0');
                b = readByte();
            }
            return negative ? -res : res;
        }
    }
}

