func main() {
	reader := bufio.NewReader(os.Stdin)

	line1, _ := reader.ReadString('\n')
	var n, m int
	fmt.Sscanf(line1, "%d %d", &n, &m)

	x := make([]int, n)
	scanner := bufio.NewScanner(reader)
	scanner.Split(bufio.ScanWords)
	for i := 0; i < n; i++ {
		scanner.Scan()
		x[i], _ = strconv.Atoi(scanner.Text())
	}

	y := make([]int, m)
	for i := 0; i < m; i++ {
		scanner.Scan()
		y[i], _ = strconv.Atoi(scanner.Text())
	}

	left := make([]int, m)
	curr := 0
	for i := 0; i < n && curr < m; i++ {
		if x[i] == y[curr] {
			left[curr] = i
			curr++
		}
	}

	if curr < m {
		fmt.Println("No")
		return
	}

	right := make([]int, m)
	curr = m - 1
	for i := n - 1; i >= 0 && curr >= 0; i-- {
		if x[i] == y[curr] {
			right[curr] = i
			curr--
		}
	}

	possible := false
	for i := 0; i < m; i++ {
		if left[i] < right[i] {
			possible = true
			break
		}
	}

	if possible {
		fmt.Println("Yes")
	} else {
		fmt.Println("No")
	}
}

import sys

class Solution:
    def optimalTreasure(self, grid: list[list[int]]) -> int:
        if not grid or not grid[0]:
            return 0
        m, n = len(grid), len(grid[0])
        dp = [[[float('-inf')] * 3 for _ in range(n)] for _ in range(m)]

        val = grid[0][0]
        if val >= 0:
            dp[0][0][0] = val
            dp[0][0][1] = val
            dp[0][0][2] = val
        else:
            dp[0][0][0] = val
            dp[0][0][1] = 0
            dp[0][0][2] = 0

        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue

                val = grid[i][j]
                prev_states = []
                if i > 0:
                    prev_states.append(dp[i-1][j])
                if j > 0:
                    prev_states.append(dp[i][j-1])

                for state in prev_states:
                    dp[i][j][0] = max(dp[i][j][0], state[0] + val)

                    if val < 0:
                        dp[i][j][1] = max(dp[i][j][1], state[0], state[1] + val)
                        dp[i][j][2] = max(dp[i][j][2], state[1], state[2] + val)
                    else:
                        dp[i][j][1] = max(dp[i][j][1], state[1] + val)
                        dp[i][j][2] = max(dp[i][j][2], state[2] + val)

        return max(dp[m-1][n-1])

