class Solution:
    def findUniqueSignal(self, signals: List[int], w: int) -> int:
        window_count = {}

        n = len(signals)
        for i in range(n - w + 1):
            window = signals[i:i+w]
            unique_in_window = set(window)
            for val in unique_in_window:
                if val not in window_count:
                    window_count[val] = 0
                window_count[val] += 1

        result = -1
        for val, count in window_count.items():
            if count == 1:
                result = max(result, val)

        return result

