    string sequence;
    int n;
    cin >> sequence >> n;

    Solution solution;
    bool result = solution.findUniformSegment(sequence, n);

    if (result) {
        cout << "true" << endl;
    } else {
        cout << "false" << endl;
    }

    return 0;
}

