        while not input_data[idx].endswith("],"):
            scores_str += input_data[idx]
            idx += 1
        scores_str += input_data[idx]
        scores_str = scores_str.rstrip(',')
        idx += 1
    else:
        scores_str = input_data[idx]
        idx += 1

    scores_str = scores_str.replace("scores=", "").replace("[", "").replace("]", "").replace(",", " ")
    scores = [int(x) for x in scores_str.split()]

    p_val = 0
    n_val = 0

    while idx < len(input_data):
        token = input_data[idx].replace(",", "")
        if "p=" in token:
            p_val = int(token.split("=")[1])
