package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"math"
	"os"
)

func solve() {
	input, err := ioutil.ReadAll(os.Stdin)
	if err != nil {
		return
	}

	var fields [][]int
	err = json.Unmarshal(input, &fields)
	if err != nil {
		return
	}

	if len(fields) == 0 {
		fmt.Printf("%.5f\n", 0.0)
		return
	}

	minY := math.MaxFloat64
	maxY := -math.MaxFloat64
	totalArea := 0.0

	for _, f := range fields {
		y := float64(f[1])
		s := float64(f[2])
		if y < minY {
			minY = y
		}
		if y+s > maxY {
			maxY = y+s
		}
		totalArea += s * s
	}

	target := totalArea / 2.0
	low := minY
	high := maxY

	for i := 0; i < 100; i++ {
		mid := (low + high) / 2.0
		areaBelow := 0.0
		for _, f := range fields {
			y := float64(f[1])
			s := float64(f[2])
			side := float64(f[2])

			if mid <= y {
				areaBelow += 0
			} else if mid >= y+s {
				areaBelow += side * side
			} else {
				areaBelow += side * (mid - y)
			}
		}

		if areaBelow < target {
			low = mid
		} else {
			high = mid
		}
	}

	fmt.Printf("%.5f\n", low)
}

func main() {
	solve()
}

