                        res += dp(idx + 1, next_is_less, True, next_sum, next_prod_mod, target_sum)

                memo[state] = res
                return res

            total = 0
            max_sum = 9 * L
            for s in range(1, max_sum + 1):
                memo = {}
                count = dp(0, False, False, 0, 0, s)
                total += count
            return total

        return solve(end) - solve(start - 1)

