import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    x = [int(val) for val in input_data[1:]]

    y = [0] * n
    active_knights_count = [0] * (n + 2)

    total_reduction = 0

    for i in range(n):
        current_coins = x[i]

        if i > 0:
            total_reduction += 1

        final_coins = current_coins - (total_reduction - active_knights_count[i])

        if final_coins < 0:
            final_coins = 0

        y[i] = final_coins

        if final_coins > 0:
            expiry_year = i + final_coins
            if expiry_year < n:
                active_knights_count[expiry_year] += 1

        active_knights_count[i+1] += active_knights_count[i]

    res = [0] * n
    donated_count = [0] * (n + 1)

    for i in range(n):
        coins_at_knighting = x[i]
        received = 0
        if i > 0:
            received = i - donated_count[i]

        coins_after_receiving = coins_at_knighting + received

        loss = (n - 1) - i
        if coins_after_receiving < loss:
            actual_loss = coins_after_receiving
            if i + 1 + actual_loss <= n:
                donated_count[i + 1 + actual_loss] += 1
        else:
            actual_loss = loss

        res[i] = coins_after_receiving - actual_loss
        donated_count[i+1] += donated_count[i]

    print(*(res))

def main():
    solve()

if __name__ == "__main__":
    main()

