def main():
    N = int(input())
    D = input().strip()

    def majority(a, b, c):
        if a + b + c >= 2:
            return 1
        else:
            return 0

    def build_tree(data, level):
        if level == 0:
            return [int(x) for x in data]

        prev = build_tree(data, level - 1)
        result = []
        for i in range(0, len(prev), 3):
            val = majority(prev[i], prev[i+1], prev[i+2])
            result.append(val)
        return result

    def min_cost_to_flip(data, level):
        if level == 0:
            return [1] * len(data)

        prev_costs = min_cost_to_flip(data, level - 1)
        prev_values = build_tree(data, level - 1)

        result = []
        for i in range(0, len(prev_values), 3):
            v0, v1, v2 = prev_values[i], prev_values[i+1], prev_values[i+2]
            c0, c1, c2 = prev_costs[i], prev_costs[i+1], prev_costs[i+2]

            current = majority(v0, v1, v2)

            costs = []

            flip0 = c0
            flip1 = c1
            flip2 = c2

            new_v0 = 1 - v0
            new_v1 = 1 - v1
            new_v2 = 1 - v2

            if majority(new_v0, v1, v2) != current:
                costs.append(flip0)
            if majority(v0, new_v1, v2) != current:
                costs.append(flip1)
            if majority(v0, v1, new_v2) != current:
                costs.append(flip2)
            if majority(new_v0, new_v1, v2) != current:
                costs.append(flip0 + flip1)
            if majority(new_v0, v1, new_v2) != current:
                costs.append(flip0 + flip2)
            if majority(v0, new_v1, new_v2) != current:
                costs.append(flip1 + flip2)
            if majority(new_v0, new_v1, new_v2) != current:
                costs.append(flip0 + flip1 + flip2)

            result.append(min(costs))

        return result

    costs = min_cost_to_flip(D, N)
    print(costs[0])

