def main():
    MOD = 998244353

    N, L = map(int, input().split())
    B = input().strip()

    def solve():
        dp = [{} for _ in range(L + 1)]
        dp[0][tuple([0] * N)] = 1

        for pos in range(L):
            for state, count in dp[pos].items():
                for c in range(26):
                    ch = chr(ord('a') + c)
                    new_state = list(state)
                    for i in range(N - 1, -1, -1):
                        if B[i] == ch:
                            if i == 0:
                                new_state[i] = max(new_state[i], 1)
                            else:
                                new_state[i] = max(new_state[i], new_state[i - 1] + 1)
                        if i < N - 1:
                            new_state[i] = max(new_state[i], new_state[i + 1])

                    new_state_tuple = tuple(new_state)
                    if new_state_tuple not in dp[pos + 1]:
                        dp[pos + 1][new_state_tuple] = 0
                    dp[pos + 1][new_state_tuple] = (dp[pos + 1][new_state_tuple] + count) % MOD

        result = [0] * (N + 1)
        for state, count in dp[L].items():
            lcs_len = max(state)
            result[lcs_len] = (result[lcs_len] + count) % MOD

        return result

    def lcs_length(s1, s2):
        m, n = len(s1), len(s2)
        dp = [[0] * (n + 1) for _ in range(m + 1)]
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if s1[i - 1] == s2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1] + 1
                else:
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])
        return dp[m][n]

    def solve_v2():
        dp = [{}]
        dp[0][tuple([0] * (N + 1))] = 1

        for pos in range(L):
            dp.append({})
            for state, count in dp[pos].items():
                for c in range(26):
                    ch = chr(ord('a') + c)
                    new_state = [0] * (N + 1)
                    for j in range(N + 1):
                        new_state[j] = state[j]
                        if j > 0 and B[j - 1] == ch:
                            new_state[j] = max(new_state[j], state[j - 1] + 1)
                        if j > 0:
                            new_state[j] = max(new_state[j], new_state[j - 1])

                    new_state_tuple = tuple(new_state)
                    if new_state_tuple not in dp[pos + 1]:
                        dp[pos + 1][new_state_tuple] = 0
                    dp[pos + 1][new_state_tuple] = (dp[pos + 1][new_state_tuple] + count) % MOD

        result = [0] * (N + 1)
        for state, count in dp[L].items():
            lcs_len = state[N]
            result[lcs_len] = (result[lcs_len] + count) % MOD

        return result

    result = solve_v2()
    print(' '.join(map(str, result)))

