package main

import (
	"fmt"
)

func main() {
	var n int
	var s string
	fmt.Scan(&n)
	fmt.Scan(&s)

	positions := []int{}
	for i := 0; i < n; i++ {
		if s[i] == '1' {
			positions = append(positions, i)
		}
	}

	k := len(positions)
	if k == 0 || k == n {
		fmt.Println(0)
		return
	}

	minSwaps := int(1e18)

	for start := 0; start <= n-k; start++ {
		swaps := 0
		for i := 0; i < k; i++ {
			targetPos := start + i
			actualPos := positions[i]
			swaps += abs(targetPos - actualPos)
		}
		if swaps < minSwaps {
			minSwaps = swaps
		}
	}

	fmt.Println(minSwaps)
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

