import sys
from collections import deque

def main():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    s = input_data[1:]

    dist = [[-1] * n for _ in range(n)]
    queue = deque()

    for i in range(n):
        dist[i][i] = 0
        queue.append((i, i))

    for i in range(n):
        for j in range(n):
            if i != j and s[i][j] != '-':
                if dist[i][j] == -1:
                    dist[i][j] = 1
                    queue.append((i, j))

    adj_out = [[] for _ in range(n)]
    adj_in = [[] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if s[i][j] != '-':
                char_idx = ord(s[i][j]) - ord('a')
                adj_out[i].append((j, char_idx))
                adj_in[j].append((i, char_idx))

    while queue:
        u, v = queue.popleft()
        d = dist[u][v]

        for prev_u, char_u in adj_in[u]:
            for next_v, char_v in adj_out[v]:
                if char_u == char_v:
                    if dist[prev_u][next_v] == -1:
                        dist[prev_u][next_v] = d + 2
                        queue.append((prev_u, next_v))

    for row in dist:
        print(*(row))

if __name__ == "__main__":
    main()

