def main():
    N, M = map(int, input().split())

    graph = [[] for _ in range(N + 1)]

    for _ in range(M):
        p, q, e = map(int, input().split())
        graph[p].append((q, e))
        graph[q].append((p, e))

    min_xor = float('inf')

    def dfs(node, target, visited, current_xor):
        nonlocal min_xor

        if node == target:
            min_xor = min(min_xor, current_xor)
            return

        for neighbor, edge_value in graph[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                dfs(neighbor, target, visited, current_xor ^ edge_value)
                visited.remove(neighbor)

    visited = {1}
    dfs(1, N, visited, 0)

    print(min_xor)

