using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    long long R, C;
    if (!(cin >> N >> R >> C)) return 0;
    string T;
    cin >> T;

    vector<long long> dr(N + 1, 0);
    vector<long long> dc(N + 1, 0);

    for (int i = 0; i < N; ++i) {
        dr[i + 1] = dr[i];
        dc[i + 1] = dc[i];
        if (T[i] == 'N') dr[i + 1]--;
        else if (T[i] == 'S') dr[i + 1]++;
        else if (T[i] == 'W') dc[i + 1]--;
        else if (T[i] == 'E') dc[i + 1]++;
    }

    string res = "";
    set<pair<long long, long long>> active_offsets;
    active_offsets.insert({0, 0});

    for (int t = 1; t <= N; ++t) {
        long long target_offset_r = R - dr[t];
        long long target_offset_c = C - dc[t];

        if (active_offsets.count({target_offset_r, target_offset_c})) {
            res += '1';
        } else {
            res += '0';
        }

        long long current_origin_offset_r = -dr[t];
        long long current_origin_offset_c = -dc[t];
        active_offsets.insert({current_origin_offset_r, current_origin_offset_c});
    }

    cout << res << endl;

    return 0;
}

