def main():
    n, m = map(int, input().split())

    parent = list(range(n + 1))

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        px, py = find(x), find(y)
        if px == py:
            return False
        parent[px] = py
        return True

    removed = 0
    for _ in range(m):
        a, b = map(int, input().split())
        if not union(a, b):
            removed += 1

    print(removed)

main()

