def main():
    T = int(input())
    for _ in range(T):
        N = int(input())
        B = list(map(int, input().split()))

        positions = {}
        for i in range(2 * N):
            species = B[i]
            if species not in positions:
                positions[species] = []
            positions[species].append(i)

        count = 0
        for x in range(1, N + 1):
            for y in range(x + 1, N + 1):
                pos_x = positions[x]
                pos_y = positions[y]

                if abs(pos_x[0] - pos_x[1]) == 1:
                    continue
                if abs(pos_y[0] - pos_y[1]) == 1:
                    continue

                all_pos = sorted(pos_x + pos_y)

                valid = False
                for mask in range(4):
                    x_indices = []
                    y_indices = []
                    for bit in range(4):
                        if mask & (1 << bit):
                            x_indices.append(all_pos[bit])
                        else:
                            y_indices.append(all_pos[bit])

                    if len(x_indices) == 2 and len(y_indices) == 2:
                        if abs(x_indices[0] - x_indices[1]) == 1 and abs(y_indices[0] - y_indices[1]) == 1:
                            valid = True
                            break

                if valid:
                    count += 1

        print(count)

main()

