using namespace std;

int main() {
    long long T;
    cin >> T;

    long long count = 0;
    long long power_of_2 = 2;

    while (power_of_2 <= T) {
        long long max_r_squared = T / power_of_2;
        long long max_r = (long long)sqrt((double)max_r_squared);

        while ((max_r + 1) * (max_r + 1) <= max_r_squared) {
            max_r++;
        }
        while (max_r * max_r > max_r_squared) {
            max_r--;
        }

        long long odd_count = (max_r + 1) / 2;
        count += odd_count;

        if (power_of_2 > T / 2) break;
        power_of_2 *= 2;
    }

    cout << count << endl;

    return 0;
}

