import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    p = list(map(int, input_data[1:]))

    dp = [0] * (n + 1)

    stack = []

    for i in range(1, n + 1):
        val = p[i-1]

        res = dp[i-1] + val

        if i >= 2:
            res = max(res, dp[i-2])

        dp[i] = res

    print(dp[n])

def main():
    solve()

if __name__ == "__main__":
    main()

