package main

import (
	"bufio"
	"fmt"
	"os"
	"sort"
)

func solve() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)

	x := make([]int64, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &x[i])
	}
	y := make([]int64, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &y[i])
	}

	knownX := make([]int64, 0)
	missX := 0
	for _, v := range x {
		if v == -1 {
			missX++
		} else {
			knownX = append(knownX, v)
		}
	}

	knownY := make([]int64, 0)
	missY := 0
	for _, v := range y {
		if v == -1 {
			missY++
		} else {
			knownY = append(knownY, v)
		}
	}

	sort.Slice(knownX, func(i, j int) bool { return knownX[i] < knownX[j] })
	sort.Slice(knownY, func(i, j int) bool { return knownY[i] > knownY[j] })

	candidates := make(map[int64]struct{})
	for _, vx := range knownX {
		for _, vy := range knownY {
			candidates[vx+vy] = struct{}{}
		}
	}

	if len(knownX) > 0 {
		candidates[knownX[len(knownX)-1]] = struct{}{}
	}
	if len(knownY) > 0 {
		candidates[knownY[0]] = struct{}{}
	}

	for s := range candidates {
		if check(s, knownX, knownY, missX, missY, n) {
			fmt.Println("Yes")
			return
		}
	}

	if len(knownX) == 0 && len(knownY) == 0 {
		fmt.Println("Yes")
		return
	}

	fmt.Println("No")
}

func check(s int64, knownX, knownY []int64, missX, missY, n int) bool {
	kx := len(knownX)
	ky := len(knownY)

	for _, v := range knownX {
		if v > s {
			return false
		}
	}
	for _, v := range knownY {
		if v > s {
			return false
		}
	}

	i, j := 0, 0
	matched := 0
	for i < kx && j < ky {
		sum := knownX[i] + knownY[j]
		if sum == s {
			matched++
			i++
			j++
		} else if sum < s {
			i++
		} else {
			j++
		}
	}

	remX := kx - matched
	remY := ky - matched

	if remX > missY {
		return false
	}
	if remY > missX {
		return false
	}

	totalUsed := matched + remX + remY
	if totalUsed > n {
		return false
	}

	return true
}

func main() {
	solve()
}

